#!/usr/bin/env bash
set -euo pipefail
python -c "from pathlib import Path; p=Path('kubernetes/apis/sandbox/v1alpha1/batchsandbox_types.go'); old='	// Replicas is the number of desired replicas.
	// +kubebuilder:validation:Required
	// +kubebuilder:validation:Minimum=0
	// +kubebuilder:default=1
	Replicas *int32 `json:"replicas,omitempty"`'; new=old+'
	// PriorityClassName selects the pod priority class for sandbox pods.
	// +optional
	// +kubebuilder:validation:Optional
	PriorityClassName string `json:"priorityClassName,omitempty"`'; s=p.read_text(); p.write_text(s.replace(old,new,1))"
